INSERT INTO events (id,project_id,source_id,title,summary,raw_text,event_type,category,severity,status,event_timestamp) VALUES
INSERT INTO events (id,project_id,source_id,title,summary,raw_text,event_type,category,severity,status,event_timestamp) VALUES
('d2000000-0000-0000-0000-000000000001','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','Architecture decision: App Router and Supabase','App Router chosen over T3 stack. No Prisma.','Architecture: App Router wins.','decision','product_decision','medium','resolved',now() - interval '88 days'),
('d2000000-0000-0000-0000-000000000002','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','GitHub OAuth redirect_uri mismatch in local dev','Local OAuth fails - localhost not registered in GitHub app.','OAuth redirect mismatch.','bug_note','auth_oauth','medium','resolved',now() - interval '85 days'),
('d2000000-0000-0000-0000-000000000003','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','V1 roadmap: 8-week build plan to closed beta','8-week plan: auth, webhooks, dashboard, onboarding, beta.','V1 roadmap 8-week plan.','decision','roadmap','low','resolved',now() - interval '82 days'),
('d2000000-0000-0000-0000-000000000004','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','Webhook ingestion latency spikes under load','p99 4.2s at 50 concurrent calls. Supabase free-tier cold starts.','Webhook p99=4.2s.','bug_note','bug','medium','resolved',now() - interval '78 days'),
('d2000000-0000-0000-0000-000000000005','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','App Store submission requirements research','App Store: 4.2 minimum functionality, privacy policy, demo account.','App Store reqs researched.','reference','app_store','low','open',now() - interval '75 days'),
('d2000000-0000-0000-0000-000000000006','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','Auth session not persisting after Safari page refresh','Safari clears localStorage aggressively. Session lost on hard refresh.','Safari kills session. Fix: cookie persist.','bug_note','auth_oauth','high','resolved',now() - interval '70 days'),
('d2000000-0000-0000-0000-000000000007','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','Competitor analysis: BuildPulse and Trunk vs VCTRL','BuildPulse=analytics, Trunk=quality. None own real-time alerting.','Competitors: no one owns real-time alerting.','insight','competitor_insight','low','resolved',now() - interval '68 days'),
('d2000000-0000-0000-0000-000000000008','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000001','Pricing model first draft: usage-based vs seat-based','Seat-based wins: solo free, team 12, pro 39 per month.','Pricing: seat-based.','decision','pricing','medium','open',now() - interval '65 days'),
('d2000000-0000-0000-0000-000000000009','a1b2c3d4-0000-0000-0000-000000000001',NULL,'Real-time build status drops on reconnect','Supabase Realtime no auto-resubscribe after network drop.','Realtime: no auto-resubscribe.','bug_note','bug','high','in_progress',now() - interval '60 days'),
('d2000000-0000-0000-0000-000000000010','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','Beta cohort 2: Connect repo step unclear','5 of 8 users skipped Connect repo step. Need tooltip.','Beta 2: Connect repo confusing.','feedback','beta_feedback','high','open',now() - interval '58 days'),
('d2000000-0000-0000-0000-000000000011','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','Webhook latency improved 60pct after Supabase upgrade','Pro plan: p99 dropped from 4.2s to 1.7s. Cold starts gone.','Supabase Pro: p99 4.2s to 1.7s.','update','bug','medium','resolved',now() - interval '55 days'),
('d2000000-0000-0000-0000-000000000012','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','Narrowed GitHub OAuth scope to repo:status only','Changed scope repo to repo:status. Trust score improved.','OAuth scope narrowed.','decision','auth_oauth','medium','resolved',now() - interval '52 days'),
('d2000000-0000-0000-0000-000000000013','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000003','BLOCKER: Build events fail when webhook payload exceeds 1MB','Edge function times out on payloads over 1MB. Event lost.','Critical: webhook over 1MB dropped.','bug_note','launch_blocker','critical','open',now() - interval '48 days'),
('d2000000-0000-0000-0000-000000000014','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','Beta users confused by team vs pro plan distinction','7 of 12 users confused about team vs pro plans.','Pricing confusion: team vs pro.','feedback','beta_feedback','medium','open',now() - interval '45 days'),
('d2000000-0000-0000-0000-000000000015','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000003','Supabase RLS policies tightened for multi-tenant','Found 2 cross-project leakage vectors. Fixed both.','RLS audit: 2 vectors fixed.','decision','product_decision','high','resolved',now() - interval '42 days'),
('d2000000-0000-0000-0000-000000000016','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','App Store privacy policy drafted, legal review pending','90-day retention, GDPR compliance. Sent to legal.','Privacy policy drafted.','update','app_store','medium','in_progress',now() - interval '40 days'),
('d2000000-0000-0000-0000-000000000017','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','Beta feedback: dashboard too noisy, want simpler view','Beta 3 (6 devs). Too many metrics. Users want failure-only view.','Beta 3: dashboard too noisy.','feedback','beta_feedback','medium','open',now() - interval '38 days'),
('d2000000-0000-0000-0000-000000000018','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000002','CRITICAL: Token refresh race condition causes 401','Two tabs both refresh. One gets 401 silent logout. Affects 5pct.','Token refresh race condition.','bug_note','auth_oauth','critical','open',now() - interval '35 days'),
('d2000000-0000-0000-0000-000000000019','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Sprint 3 retro: Slack deferred to V2','Slack delays launch 3 weeks. V1 ships email notifications only.','Sprint 3: Slack deferred.','decision','roadmap','medium','resolved',now() - interval '33 days'),
('d2000000-0000-0000-0000-000000000020','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Pricing revised: Starter Growth Team tiers','Starter free, Growth 9/mo, Team 29/mo. Pro tier dropped.','Pricing: Starter/Growth/Team.','decision','pricing','medium','resolved',now() - interval '30 days'),
('d2000000-0000-0000-0000-000000000021','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Token refresh race condition resolved, localStorage mutex','localStorage mutex serializes token refresh across tabs.','Token refresh race fixed.','update','auth_oauth','critical','resolved',now() - interval '28 days'),
('d2000000-0000-0000-0000-000000000022','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','App Store rejected - Guideline 4.2 Minimum Functionality','No demo mode. Add demo/guest mode with sample build data.','App Store rejection: demo mode needed.','bug_note','app_store','high','in_progress',now() - interval '25 days'),
('d2000000-0000-0000-0000-000000000023','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','BLOCKER: Demo mode required for App Store and onboarding','Demo mode needed for App Store 4.2 and onboarding. Must ship.','Demo mode = launch blocker.','blocker','launch_blocker','high','open',now() - interval '22 days'),
('d2000000-0000-0000-0000-000000000024','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Dashboard slow 3.2s, Lighthouse score 61','LCP 3.2s, TBT 280ms. Fix: lazy charts, suspense. Target 80+.','Dashboard: Lighthouse=61.','bug_note','bug','medium','in_progress',now() - interval '20 days'),
('d2000000-0000-0000-0000-000000000025','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Beta cohort 4: NPS 47, real-time alerts validated','NPS 47 up from 31. Core value: real-time alerting confirmed.','Beta 4 NPS: 47.','feedback','beta_feedback','low','resolved',now() - interval '18 days'),
('d2000000-0000-0000-0000-000000000026','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','BuildPulse launched Slack, increased V2 urgency','BuildPulse shipped Slack. V2 Slack timeline more urgent.','BuildPulse shipped Slack.','insight','competitor_insight','medium','open',now() - interval '16 days'),
('d2000000-0000-0000-0000-000000000027','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000004','Pricing A/B test: annual discount vs monthly','Monthly vs monthly+annual (save 20pct). Testing soft launch week.','Pricing A/B: annual option.','decision','pricing','low','open',now() - interval '15 days'),
('d2000000-0000-0000-0000-000000000028','a1b2c3d4-0000-0000-0000-000000000001',NULL,'Added pre-OAuth context screen, reduces friction','Auth completion improved from 71pct to 89pct. Biggest UX win.','Pre-OAuth context shipped.','update','auth_oauth','medium','resolved',now() - interval '11 days'),
('d2000000-0000-0000-0000-000000000029','a1b2c3d4-0000-0000-0000-000000000001',NULL,'Webhook payload over 1MB resolved, streaming parse shipped','Streaming parse, 2MB limit, 413 on oversize. Critical blocker closed.','Webhook over 1MB fix shipped.','update','launch_blocker','critical','resolved',now() - interval '9 days'),
('d2000000-0000-0000-0000-000000000030','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000005','Launch checklist: 3 open items remain before launch','Open: demo data, App Store resubmit pending legal, webhook rate limiting.','Launch checklist: 3 open.','update','launch_blocker','high','open',now() - interval '6 days'),
('d2000000-0000-0000-0000-000000000031','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000005','Dashboard performance improved: Lighthouse up to 84','Lazy charts and suspense boundaries. Lighthouse 61 to 84.','Dashboard: Lighthouse 84.','update','bug','medium','resolved',now() - interval '5 days'),
('d2000000-0000-0000-0000-000000000032','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000005','Post-launch V2 scope locked: Slack teams analytics','V2: Slack + team accounts + analytics + GitHub Actions. Stripe V2.1.','V2 scope locked.','decision','roadmap','medium','open',now() - interval '4 days'),
('d2000000-0000-0000-0000-000000000033','a1b2c3d4-0000-0000-0000-000000000001',NULL,'Sign-out does not clear server-side session cookie','Back-button re-auths after sign-out. Server cookie not cleared.','Sign-out bug: back-button re-auths.','bug_note','auth_oauth','high','open',now() - interval '3 days'),
('d2000000-0000-0000-0000-000000000034','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000005','App Store: demo seeded, resubmit pending legal sign-off','5 scenarios seeded. Reviewer login ready. Waiting on legal.','Demo ready. Waiting on legal.','update','app_store','high','in_progress',now() - interval '2 days'),
('d2000000-0000-0000-0000-000000000035','a1b2c3d4-0000-0000-0000-000000000001',NULL,'Beta: email notification delay up to 8 minutes on failures','Email delay 5-8 min. Root cause: Resend free tier rate limiting.','Email delay: Resend rate limit.','bug_note','beta_feedback','high','open',now() - interval '1 day'),
('d2000000-0000-0000-0000-000000000036','a1b2c3d4-0000-0000-0000-000000000001','b2000000-0000-0000-0000-000000000005','BLOCKER: Webhook rate limiting not enforced, vulnerable to abuse','No rate limiting. Fix: Upstash Redis, 100 req/min per project.','Critical: no webhook rate limiting.','blocker','launch_blocker','critical','open',now() - interval '2 hours');
